import React, { useState } from 'react';
import { useParams } from 'react-router-dom';
import CatalogGrid from '../components/Content/CatalogGrid';
import UsersCatalog from '../components/Content/UsersCatalog';
import MangaCatalog from '../components/Content/MangaCatalog';
import VideoCatalog from '../components/Content/VideoCatalog';
import CharactersCatalog from '../components/Content/CharactersCatalog';
import './CatalogPage.css';

const CatalogPage = () => {
  const { category } = useParams();
  const [filters, setFilters] = useState({
    type: 'all',
    sortBy: 'popular',
    genres: []
  });

  const genres = [
    'Экшен', 'Романтика', 'Драма', 'Комедия', 'Фэнтези',
    'Научная фантастика', 'Хоррор', 'Мистика', 'Приключения', 'Повседневность'
  ];

  const handleFilterChange = (filterName, value) => {
    setFilters(prev => ({
      ...prev,
      [filterName]: value
    }));
  };

  const handleGenreToggle = (genre) => {
    setFilters(prev => ({
      ...prev,
      genres: prev.genres.includes(genre)
        ? prev.genres.filter(g => g !== genre)
        : [...prev.genres, genre]
    }));
  };

  const handleApplyFilters = () => {
    console.log('Filters applied:', filters);
    // Бу ерда API чақириш ёки бошқа логика бўлиши мумкин
  };

  const handleResetFilters = () => {
    setFilters({
      type: 'all',
      sortBy: 'popular',
      genres: []
    });
  };

  // Категорияга қараб турли контент кўрсатиш
  const renderContent = () => {
    switch(category) {
      case 'users':
        return <UsersCatalog />;
      case 'characters':
        return <CharactersCatalog />;
      case 'manga':
      case 'manhwa':
      case 'manhua':
        return <MangaCatalog category={category} />;
      case 'video':
        return <VideoCatalog />;
      case 'titles':
      case 'reading-now':
      case 'collections':
      case 'reviews':
        return (
          <div className="category-specific">
            <h2>{getCategoryTitle(category)}</h2>
            <div className="coming-soon">
              <i className="fas fa-tools"></i>
              <p>Контент в разработке...</p>
              <p>Скоро здесь появится интересный контент!</p>
            </div>
          </div>
        );
      default:
        // Агар category йўқ бўлса (умумний каталог)
        return (
          <>
            <div className="filters-sidebar">
              <div className="filter-section">
                <div className="filter-header">
                  <h3><i className="fas fa-filter"></i> Фильтры</h3>
                  <button 
                    className="reset-filters-btn"
                    onClick={handleResetFilters}
                  >
                    <i className="fas fa-redo"></i> Сбросить
                  </button>
                </div>
                
                <div className="filter-group">
                  <label><i className="fas fa-book"></i> Тип</label>
                  <select 
                    value={filters.type}
                    onChange={(e) => handleFilterChange('type', e.target.value)}
                    className="filter-select"
                  >
                    <option value="all">Все типы</option>
                    <option value="Манга">Манга</option>
                    <option value="Манхва">Манхва</option>
                    <option value="Маньхуа">Маньхуа</option>
                    <option value="Видео">Видео</option>
                  </select>
                </div>
                
                <div className="filter-group">
                  <label><i className="fas fa-sort"></i> Сортировка</label>
                  <select 
                    value={filters.sortBy}
                    onChange={(e) => handleFilterChange('sortBy', e.target.value)}
                    className="filter-select"
                  >
                    <option value="popular">По популярности</option>
                    <option value="newest">Сначала новые</option>
                    <option value="rating">По рейтингу</option>
                    <option value="views">По просмотрам</option>
                    <option value="chapters">По главам</option>
                  </select>
                </div>
                
                <div className="filter-group">
                  <label><i className="fas fa-tags"></i> Жанры</label>
                  <div className="genres-grid">
                    {genres.map(genre => (
                      <button
                        key={genre}
                        className={`genre-tag ${filters.genres.includes(genre) ? 'active' : ''}`}
                        onClick={() => handleGenreToggle(genre)}
                      >
                        {genre}
                        {filters.genres.includes(genre) && (
                          <i className="fas fa-check"></i>
                        )}
                      </button>
                    ))}
                  </div>
                </div>
                
                <div className="filter-stats">
                  <div className="stat-item">
                    <span className="stat-value">{filters.genres.length}</span>
                    <span className="stat-label">Жанров выбрано</span>
                  </div>
                  <div className="stat-item">
                    <span className="stat-value">
                      {filters.type === 'all' ? 'Все' : filters.type}
                    </span>
                    <span className="stat-label">Тип</span>
                  </div>
                </div>
                
                <button 
                  className="apply-filters"
                  onClick={handleApplyFilters}
                >
                  <i className="fas fa-check-circle"></i>
                  Применить фильтры
                </button>
              </div>
            </div>
            
            <div className="catalog-main">
              <CatalogGrid filters={filters} />
            </div>
          </>
        );
    }
  };

  const getCategoryTitle = (cat) => {
    const titles = {
      'users': 'Пользователи',
      'characters': 'Персонажи',
      'titles': 'Тайтлы',
      'reading-now': 'Сейчас читают',
      'collections': 'Коллекции',
      'reviews': 'Отзывы и Рецензии',
      'manga': 'Манга',
      'oel-manga': 'OEL-манга',
      'manhwa': 'Манхва',
      'manhua': 'Маньхуа',
      'ru-manga': 'Руманга',
      'comics': 'Комикс',
      'video': 'Видео'
    };
    return titles[cat] || 'Каталог';
  };

  return (
    <div className="catalog-page">
      <div className="page-header">
        <div className="header-content">
          <h1>{getCategoryTitle(category)}</h1>
          <p>{getCategoryDescription(category)}</p>
          {category && category !== 'all' && (
            <div className="category-badge">
              <i className="fas fa-folder"></i>
              {getCategoryTitle(category)}
            </div>
          )}
        </div>
      </div>
      
      <div className="catalog-layout">
        {renderContent()}
      </div>
    </div>
  );
};

const getCategoryDescription = (cat) => {
  const descriptions = {
    'users': 'Найдите других пользователей и посмотрите их профили',
    'characters': 'Популярные персонажи из манги и аниме',
    'titles': 'Все тайтлы в одном месте',
    'reading-now': 'Что сейчас читают другие пользователи',
    'collections': 'Подборки от пользователей',
    'reviews': 'Рецензии и отзывы на контент',
    'manga': 'Лучшая японская манга',
    'oel-manga': 'Западная манга на английском языке',
    'manhwa': 'Корейские вебтуны и манхва',
    'manhua': 'Китайские комиксы',
    'ru-manga': 'Русская манга',
    'comics': 'Западные комиксы',
    'video': 'Аниме и видео контент'
  };
  return descriptions[cat] || 'Найдите свои любимые манги, манхвы и видео';
};

export default CatalogPage;
